var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 현실 전초기지, <color=#ffd34c>쉘터 No.72</color>\\n관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 임시 본부","JPN":"管理局現実前哨基地、<color=#ffd34c>シェルターNo.72</color>\\n管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>臨時本部","ENG":"[[","TWN":"管理局現世前哨站，<color=#ffd34c>72號庇護所</color>\\n管理局第4偵察戰隊<color=#ffd34c>夜叉</color>臨時總部","SCN":"管理局现世前哨站，<color=#ffd34c>72号庇护所</color>\\n管理局第4侦察战队<color=#ffd34c>夜叉</color>临时总部","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……그런 경위로, 현장에서 구조했던 구조자의 기억 소거를 완료하였습니다.","JPN":"……というわけで、現場で救助した救助者の記憶消去を行いました。","ENG":"...And so, we successfully erased the rescuee's memories regarding this incident.","TWN":"……就是這樣，現場救出的相關人員的記憶已經被抹除。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이상, 결과보고를 마치겠습니다.","JPN":"報告は以上です。","ENG":"That concludes my briefing.","TWN":"以上，本次報告到此結束。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"응, 수고했어~","JPN":"うん、お疲れ様～","ENG":"Very well, good work.","TWN":"嗯，辛苦了～"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"관리국 대 침식 작전에 협조해주셔서 감사합니다. 야크샤 부전대장님.","JPN":"管理局の対侵食作戦にご協力いただきありがとうございました、ヤクシャー副戦隊長。","ENG":"Thank you for cooperating in the Administration's anti-Corruption operation, Yaksha Deputy Commander.","TWN":"感謝你們配合管理局的侵蝕作戰。夜叉副戰隊長。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"야크샤의 협조로 민간 피해 없이, 무사히 작전을 성공할 수 있었습니다.","JPN":"ヤクシャーの協力のおかげで民間人の被害なく、無事作戦を終えることができました。","ENG":"We were able to complete the operation without any civilian casualties thanks to your cooperation.","TWN":"多虧了夜叉的配合，作戰順利完成，沒有造成任何民眾傷亡。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"글쎄? 나한테 감사할 필요는 없는 걸?","JPN":"いや、私にお礼を言う必要はないよ。","ENG":"Hmm, I don't think there's any need to thank me.","TWN":"這個嘛？你好像不用謝我？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국 전대라면 어느 곳이든 흔쾌히 작전에 협조했을 거라고 생각해.","JPN":"私たちじゃなくても、管理局の戦隊なら誰でも快く協力していたと思う。","ENG":"I believe any division of the Administration would've willingly cooperated with the operation.","TWN":"我想任何一個管理局戰隊都會願意配合作戰的。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그건 그렇지만…….","JPN":"それはそうですが……","ENG":"Yes, of course, but...","TWN":"話雖如此……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이번 작전에서 야크샤의 <color=#ffd34c>신입 전대원</color>이 큰 활약을 했다고 들었습니다.","JPN":"今回の作戦で、ヤクシャーの<color=#ffd34c>新入戦隊員</color>が大きく貢献したと聞きました。","ENG":"I heard that Yaksha's <color=#ffd34c>rookie</color> played a great role in this operation.","TWN":"聽說在這次作戰中，夜叉的<color=#ffd34c>新隊員</color>表現非常出色。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"<color=#ffd34c>그 사건</color>이후로, 전력이 약화됐다고 들었는데…….","JPN":"<color=#ffd34c>あの事件</color>以来、戦力が弱化したいう話を聞きましたが……","ENG":"I heard that your division had weakened after <color=#ffd34c>that incident</color>...","TWN":"我聽說<color=#ffd34c>那次事件</color>之後，貴戰隊的戰力損失不小。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"야크샤 전대가 순조롭게 회복하고 있는 것 같아서 마음이 놓입니다.","JPN":"ヤクシャー戦隊の戦力が順調に回復している様で、とても安心しました。","ENG":"But seeing your division recovering puts my mind at ease.","TWN":"看到夜叉戰隊恢復得很順利，我就放心了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 걱정해줘서 고맙네.","JPN":"ふふ、心配ありがとう。","ENG":"Fu fuu. Well, thank you for your concern.","TWN":"呵呵，謝謝關心。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그럼, 현실에 주둔하고 계시는 동안 도움이 필요하시다면 불러주십시오.","JPN":"では、現実に駐屯される間何かこちらがお役に立てることがありましたら、お気軽にお声がけください。","ENG":"Then, if you need any help while you're in the Normalside, please don't hesitate to call.","TWN":"那麼，如果你駐守現實世界期間需要幫助，請致電我們。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"언제든 도와드리겠습니다.","JPN":"いつでもお手伝いします。","ENG":"We'll be more than happy to help.","TWN":"我們很樂意隨時為你提供幫助。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 사건이라…….","JPN":"あの事件、ね……","ENG":"That incident...","TWN":"那次事件啊……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"야크샤 전대원 분들. 다들 진정해 주세요.","JPN":"ヤクシャー戦隊員の皆さん、落ち着いてください。","ENG":"All Yaksha members, please calm down.","TWN":"夜叉戰隊的各位。請大家冷靜一下。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"웃기지 마, 모네카!","JPN":"ふざけるな、モネカ！","ENG":"Don’t be ridiculous, Moneka!","TWN":"別開玩笑了，莫奈卡！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"지금 우리보고 이런 결정을 받아들이라는 거야?","JPN":"こんな決定を受け入れろって言うのか！","ENG":"How could you tell us to accept that decision?","TWN":"你要我們怎麼接受這個決定！？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"진정해 다니엘, 모네카는 그냥 관리국의 의사를 전달하는 것뿐이야.","JPN":"落ち着いて、ダニエル。モネカはただ、管理局の意思を伝えただけよ。","ENG":"Calm down, Daniel. Moneka is just relaying the Administration's decision.","TWN":"冷靜點，丹尼爾，莫奈卡只是在轉達​​管理局的意思。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"모네카한테 화내봤자, 아무 의미 없어.","JPN":"モネカに怒っても意味ないもの。","ENG":"Getting angry at Moneka will change nothing.","TWN":"對莫奈卡發脾氣，沒有任何意義。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"그렇지만 누님!","JPN":"でも姉貴！","ENG":"But...!","TWN":"但是姊姊！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"저도 다니엘의 생각에 찬성이에요, 스위프트 부전대장님.","JPN":"私もダニエルと同意見です、スウィフト副戦隊長。","ENG":"I agree with Daniel, Deputy Commander.","TWN":"我也贊成丹尼爾的想法，斯威福特副戰隊長。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};